import React, { useEffect, useRef, useState } from 'react';
import './App.css';

// ── Types ──────────────────────────────────────────────────
interface Project {
  title: string;
  description: string;
  tech: string[];
  link?: string;
  year: string;
}

interface Experience {
  role: string;
  company: string;
  period: string;
  description: string[];
  type: 'internship' | 'part-time' | 'club';
}

// ── Data ───────────────────────────────────────────────────
const SKILLS = {
  Languages: ['TypeScript', 'JavaScript', 'PHP', 'Java', 'Dart'],
  Frontend: ['React', 'React Native', 'Blade', 'HTML/CSS'],
  Backend: ['Laravel', 'Node.js', 'REST APIs'],
  Tools: ['Git', 'Android Studio', 'MySQL', 'SQLite', 'Figma'],
};

const PROJECTS: Project[] = [
  {
    title: 'EV Charging Station Finder',
    description:
      'React Native app for locating EV charging stations across Malaysia. Features SQLite local storage, map integration with sample locations like KLCC and Mid Valley, and a clean TypeScript-first codebase.',
    tech: ['React Native', 'TypeScript', 'SQLite', 'Android Studio'],
    year: '2025',
  },
  {
    title: 'Health Monitoring Platform',
    description:
      'Full-stack hackathon project featuring live vitals monitoring, AI-powered fall detection via vision API, and an emergency coordinator dashboard. Built with a React frontend and FastAPI backend.',
    tech: ['React', 'FastAPI', 'Anthropic API', 'WebSockets'],
    year: '2025',
  },
  {
    title: 'Urban Foundation Guardian',
    description:
      'Geotechnical AI platform using SPT borehole data to visualise soil risk for construction sites across Malaysia. Delivered a full pitch deck and demo for a developer CEO audience.',
    tech: ['React', 'Python', 'AI/ML', 'Data Visualisation'],
    year: '2025',
  },
  {
    title: 'DavidProperty',
    description:
      'Full-stack property listing web application built with Laravel 8 and React. Includes authentication guards, Eloquent ORM, Gates & Policies, and a React + Axios frontend migrated from Vue.',
    tech: ['Laravel', 'React', 'MySQL', 'Laravel Mix'],
    year: '2024',
  },
];

const EXPERIENCES: Experience[] = [
  {
    role: 'Software Engineering Industrial Intern',
    company: 'Upcoming — 1-Year Competitive Program',
    period: '2025 – 2026',
    description: [
      'Selected for a competitive one-year industrial internship replacing the entire third year of study.',
      'Full-time industry engagement across full-stack and mobile development domains.',
      'Among a cohort of UTAR students chosen based on academic and project portfolio.',
    ],
    type: 'internship',
  },
  {
    role: 'Part-Time Accounting Assistant',
    company: 'Freelance / SME',
    period: '2023 – 2024',
    description: [
      'Managed bookkeeping and accounts payable/receivable for small business clients.',
      'Prepared monthly financial summaries and reconciliations.',
    ],
    type: 'part-time',
  },
  {
    role: 'Co-Founder & Treasurer',
    company: 'UTAR Leo Club',
    period: '2023 – 2024',
    description: [
      "Co-founded the UTAR Leo Club, establishing the club's financial framework from scratch.",
      'Managed budgets, member dues, and event expenditures across multiple community projects.',
    ],
    type: 'club',
  },
];

// ── Hooks ──────────────────────────────────────────────────
function useIntersection(threshold = 0.15) {
  const ref = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [threshold]);

  return { ref, visible };
}

// ── Components ─────────────────────────────────────────────

function Nav() {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const links = ['About', 'Skills', 'Projects', 'Experience', 'Contact'];

  return (
    <nav className={`nav ${scrolled ? 'nav--scrolled' : ''}`}>
      <a href="#hero" className="nav__logo">
        zen<span className="nav__logo-dot">.</span>
      </a>
      <ul className={`nav__links ${menuOpen ? 'nav__links--open' : ''}`}>
        {links.map((l) => (
          <li key={l}>
            <a
              href={`#${l.toLowerCase()}`}
              className="nav__link"
              onClick={() => setMenuOpen(false)}
            >
              {l}
            </a>
          </li>
        ))}
      </ul>
      <button
        className="nav__burger"
        onClick={() => setMenuOpen((v) => !v)}
        aria-label="Toggle menu"
      >
        <span className={menuOpen ? 'open' : ''} />
      </button>
    </nav>
  );
}

function Hero() {
  return (
    <section className="hero" id="hero">
      <div className="hero__inner">
        <p className="hero__eyebrow animate-fade-up" style={{ animationDelay: '0.05s' }}>
          Software Engineering Student · UTAR
        </p>
        <h1 className="hero__title animate-fade-up" style={{ animationDelay: '0.15s' }}>
          Hi, I'm <span className="hero__name">Zen</span>.<br />
          I build things<br />
          <em>for the web & mobile.</em>
        </h1>
        <p className="hero__sub animate-fade-up" style={{ animationDelay: '0.28s' }}>
          Full-stack &amp; mobile developer with a passion for clean code,
          thoughtful UX, and real-world problem solving — based in Malaysia.
        </p>
        <div className="hero__cta animate-fade-up" style={{ animationDelay: '0.4s' }}>
          <a href="#projects" className="btn btn--primary">View Projects</a>
          <a href="#contact" className="btn btn--ghost">Get in Touch</a>
        </div>
      </div>
      <div className="hero__index animate-fade-in" style={{ animationDelay: '0.6s' }}>
        <div className="hero__index-line" />
        <span>scroll</span>
      </div>
    </section>
  );
}

function About() {
  const { ref, visible } = useIntersection();
  return (
    <section className="section" id="about" ref={ref}>
      <div className={`about__grid ${visible ? 'is-visible' : ''}`}>
        <div className="about__label">
          <span className="label-tag">01 / About</span>
        </div>
        <div className="about__content">
          <h2 className="section__heading">
            A developer who cares about the craft.
          </h2>
          <p className="about__body">
            I'm a Year 3 Software Engineering student at UTAR, currently preparing
            for a competitive one-year industrial internship that replaces my
            entire third year — a program chosen for students who are serious about
            their craft.
          </p>
          <p className="about__body">
            My stack spans <strong>React, React Native, Laravel, and TypeScript</strong>.
            I've shipped mobile apps, full-stack web platforms, and AI-integrated
            projects — from solo assignments to hackathon team builds. Outside
            code, I co-founded the UTAR Leo Club and have a background in
            part-time accounting, which gives me an eye for both structure and detail.
          </p>
          <p className="about__body">
            I believe great software is precise, empathetic, and built with intent.
          </p>
          <div className="about__facts">
            <div className="about__fact">
              <span className="about__fact-num">3+</span>
              <span className="about__fact-label">Years Coding</span>
            </div>
            <div className="about__fact">
              <span className="about__fact-num">10+</span>
              <span className="about__fact-label">Projects Built</span>
            </div>
            <div className="about__fact">
              <span className="about__fact-num">MY</span>
              <span className="about__fact-label">Based in Malaysia</span>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

function Skills() {
  const { ref, visible } = useIntersection();
  return (
    <section className="section section--alt" id="skills" ref={ref}>
      <div className={`skills__inner ${visible ? 'is-visible' : ''}`}>
        <div className="section__header">
          <span className="label-tag">02 / Skills</span>
          <h2 className="section__heading">What I work with.</h2>
        </div>
        <div className="skills__grid">
          {Object.entries(SKILLS).map(([category, items], ci) => (
            <div
              className="skills__group"
              key={category}
              style={{ animationDelay: `${ci * 0.1}s` }}
            >
              <h3 className="skills__category">{category}</h3>
              <ul className="skills__list">
                {items.map((skill) => (
                  <li key={skill} className="skills__item">
                    {skill}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

function Projects() {
  const { ref, visible } = useIntersection();
  return (
    <section className="section" id="projects" ref={ref}>
      <div className={`projects__inner ${visible ? 'is-visible' : ''}`}>
        <div className="section__header">
          <span className="label-tag">03 / Projects</span>
          <h2 className="section__heading">Things I've built.</h2>
        </div>
        <div className="projects__grid">
          {PROJECTS.map((p, i) => (
            <article
              className="project-card"
              key={p.title}
              style={{ animationDelay: `${i * 0.1}s` }}
            >
              <div className="project-card__top">
                <span className="project-card__year">{p.year}</span>
                {p.link && (
                  <a
                    href={p.link}
                    target="_blank"
                    rel="noreferrer"
                    className="project-card__link"
                  >
                    ↗
                  </a>
                )}
              </div>
              <h3 className="project-card__title">{p.title}</h3>
              <p className="project-card__desc">{p.description}</p>
              <div className="project-card__tech">
                {p.tech.map((t) => (
                  <span key={t} className="tech-tag">{t}</span>
                ))}
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

function Experience() {
  const { ref, visible } = useIntersection();
  return (
    <section className="section section--alt" id="experience" ref={ref}>
      <div className={`experience__inner ${visible ? 'is-visible' : ''}`}>
        <div className="section__header">
          <span className="label-tag">04 / Experience</span>
          <h2 className="section__heading">Where I've been.</h2>
        </div>
        <div className="timeline">
          {EXPERIENCES.map((exp, i) => (
            <div
              className="timeline__item"
              key={exp.role}
              style={{ animationDelay: `${i * 0.12}s` }}
            >
              <div className="timeline__meta">
                <span className="timeline__period">{exp.period}</span>
                <span className={`timeline__badge timeline__badge--${exp.type}`}>
                  {exp.type === 'internship'
                    ? 'Internship'
                    : exp.type === 'part-time'
                    ? 'Part-time'
                    : 'Leadership'}
                </span>
              </div>
              <div className="timeline__body">
                <h3 className="timeline__role">{exp.role}</h3>
                <p className="timeline__company">{exp.company}</p>
                <ul className="timeline__desc">
                  {exp.description.map((d) => (
                    <li key={d}>{d}</li>
                  ))}
                </ul>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

function Contact() {
  const { ref, visible } = useIntersection();
  return (
    <section className="section" id="contact" ref={ref}>
      <div className={`contact__inner ${visible ? 'is-visible' : ''}`}>
        <div className="section__header">
          <span className="label-tag">05 / Contact</span>
        </div>
        <h2 className="contact__heading">
          Let's work<br /><em>together.</em>
        </h2>
        <p className="contact__sub">
          I'm currently open to internship opportunities and project collaborations.
          If you'd like to connect, my inbox is always open.
        </p>
        <div className="contact__links">
          <a href="mailto:zen@email.com" className="contact__link">
            <span className="contact__link-icon">✉</span>
            zen@email.com
          </a>
          <a
            href="https://github.com/"
            target="_blank"
            rel="noreferrer"
            className="contact__link"
          >
            <span className="contact__link-icon">⌥</span>
            GitHub
          </a>
          <a
            href="https://linkedin.com/in/"
            target="_blank"
            rel="noreferrer"
            className="contact__link"
          >
            <span className="contact__link-icon">in</span>
            LinkedIn
          </a>
        </div>
      </div>
    </section>
  );
}

function Footer() {
  return (
    <footer className="footer">
      <span>© {new Date().getFullYear()} Zen · Built with React + TypeScript</span>
    </footer>
  );
}

// ── App ────────────────────────────────────────────────────
export default function App() {
  return (
    <>
      <Nav />
      <main>
        <Hero />
        <About />
        <Skills />
        <Projects />
        <Experience />
        <Contact />
      </main>
      <Footer />
    </>
  );
}
